// src/lib/errors.js
const sendError = (res, status, code, message) => {
  res.status(status).json({ error: { code, message } });
};

module.exports = {
  sendError,
};

// src/modules/members/routes.js
const express = require('express');
const router = express.Router();
const membersService = require('./service');
const { sendError } = require('../../lib/errors');

router.post('/', async (req, res) => {
  const { userId, role } = req.body;
  if (!userId || !role) {
    return sendError(res, 400, 'INVALID_INPUT', 'Invalid input data');
  }
  try {
    const member = await membersService.createMember(userId, role);
    res.status(201).json({ member });
  } catch (error) {
    if (error.code === 'DUPLICATE') {
      return sendError(res, 409, 'DUPLICATE', error.message);
    }
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

// src/modules/tasks/routes.js
const express = require('express');
const router = express.Router();
const tasksService = require('./service');
const { sendError } = require('../../lib/errors');

router.post('/', async (req, res) => {
  const { description } = req.body;
  if (!description) {
    return sendError(res, 400, 'INVALID_INPUT', 'Invalid input data');
  }
  try {
    const task = await tasksService.createTask(description);
    res.status(201).json({ task });
  } catch (error) {
    if (error.code === 'DUPLICATE') {
      return sendError(res, 409, 'DUPLICATE', error.message);
    }
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.get('/', async (req, res) => {
  const { status } = req.query;
  try {
    const tasks = await tasksService.getTasks(status);
    res.json({ tasks });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.patch('/:taskId', async (req, res) => {
  const { taskId } = req.params;
  const { status } = req.body;
  if (!status || ![ 'todo', 'done' ].includes(status)) {
    return sendError(res, 400, 'INVALID_INPUT', 'Invalid input data');
  }
  try {
    const updatedTask = await tasksService.updateTask(taskId, status);
    res.json({ task: updatedTask });
  } catch (error) {
    if (error.code === 'NOT_FOUND') {
      return sendError(res, 404, 'NOT_FOUND', error.message);
    }
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

